import{_ as d,o as r,c as a,a2 as h}from"./chunks/framework.B72_uj9U.js";const b=JSON.parse('{"title":"消费电子行业供应商自评问卷（SAQ-ELE-001）","description":"","frontmatter":{},"headers":[],"relativePath":"zh/industry/electronics/saq.md","filePath":"zh/industry/electronics/saq.md"}'),e={name:"zh/industry/electronics/saq.md"};function o(_,t,n,l,s,E){return r(),a("div",null,[...t[0]||(t[0]=[h('<h1 id="消费电子行业供应商自评问卷-saq-ele-001" tabindex="-1">消费电子行业供应商自评问卷（SAQ-ELE-001） <a class="header-anchor" href="#消费电子行业供应商自评问卷-saq-ele-001" aria-label="Permalink to &quot;消费电子行业供应商自评问卷（SAQ-ELE-001）&quot;">​</a></h1><blockquote><p><strong>版本：</strong> 2025年版 · <strong>适用范围：</strong> 消费电子OEM/ODM/EMS制造商、PCB/组件供应商</p><p><strong>填写说明：</strong> 本问卷在通用SAQ（Section A–H）基础上增加电子行业专项模块，两者须同时提交。</p></blockquote><hr><p><strong>供应商信息</strong></p><table tabindex="0"><thead><tr><th>字段</th><th>填写</th></tr></thead><tbody><tr><td>工厂/公司法人名称</td><td></td></tr><tr><td>主要生产/服务地址</td><td></td></tr><tr><td>RBA VAP 编号（如有）</td><td></td></tr><tr><td>ISO 27001 认证状态</td><td></td></tr><tr><td>主要客户（前3位）</td><td></td></tr><tr><td>年营业额（人民币/美元）</td><td></td></tr><tr><td>填表人 / 职务 / 日期</td><td></td></tr></tbody></table><hr><h2 id="模块-e1-冲突矿产-3tg-钴" tabindex="-1">模块 E1　冲突矿产（3TG + 钴） <a class="header-anchor" href="#模块-e1-冲突矿产-3tg-钴" aria-label="Permalink to &quot;模块 E1　冲突矿产（3TG + 钴）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>问题</th><th>是</th><th>否</th><th>不适用</th><th>备注</th></tr></thead><tbody><tr><td>E1.1</td><td>贵公司产品中是否可能含有锡（Sn）、钽（Ta）、钨（W）、金（Au）？</td><td></td><td></td><td></td><td></td></tr><tr><td>E1.2</td><td>贵公司产品中是否可能含有钴（Co，用于锂电池等）？</td><td></td><td></td><td></td><td></td></tr><tr><td>E1.3</td><td>是否已完成最新版**冲突矿产申报表（CMRT）**并可提供？</td><td></td><td></td><td></td><td></td></tr><tr><td>E1.4</td><td>CMRT中的冶炼厂是否全部为RMI（责任矿产倡议）认证冶炼厂？</td><td></td><td></td><td></td><td></td></tr><tr><td>E1.5</td><td>如有非认证冶炼厂，是否有改善或替换计划？</td><td></td><td></td><td></td><td></td></tr><tr><td>E1.6</td><td>钴供应链溯源是否延伸至矿山级别？</td><td></td><td></td><td></td><td></td></tr><tr><td>E1.7</td><td>是否要求一级物料供应商提交CMRT，并核验其内容？</td><td></td><td></td><td></td><td></td></tr></tbody></table><hr><h2 id="模块-e2-数据安全与知识产权保护" tabindex="-1">模块 E2　数据安全与知识产权保护 <a class="header-anchor" href="#模块-e2-数据安全与知识产权保护" aria-label="Permalink to &quot;模块 E2　数据安全与知识产权保护&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>问题</th><th>是</th><th>否</th><th>部分</th><th>备注</th></tr></thead><tbody><tr><td>E2.1</td><td>是否具备信息安全管理体系（ISO 27001认证或等效体系）？</td><td></td><td></td><td></td><td></td></tr><tr><td>E2.2</td><td>所有处理客户设计文件的员工是否签署了保密协议（NDA）？</td><td></td><td></td><td></td><td></td></tr><tr><td>E2.3</td><td>客户的CAD文件、BOM单、固件代码是否存储在访问受控的系统中（非普通文件服务器）？</td><td></td><td></td><td></td><td></td></tr><tr><td>E2.4</td><td>是否实施了最小权限原则（员工只能访问其工作所需的客户IP）？</td><td></td><td></td><td></td><td></td></tr><tr><td>E2.5</td><td>是否部署了数据防泄漏（DLP）工具，防止客户IP向外传输？</td><td></td><td></td><td></td><td></td></tr><tr><td>E2.6</td><td>员工个人设备（手机）是否被禁止在含有客户IP的工作区域拍照？</td><td></td><td></td><td></td><td></td></tr><tr><td>E2.7</td><td>是否有安全的文件销毁流程（硬盘销毁、文件碎纸）？</td><td></td><td></td><td></td><td></td></tr><tr><td>E2.8</td><td>过去3年内是否发生过任何客户数据或IP泄露事件？</td><td></td><td></td><td></td><td></td></tr></tbody></table><hr><h2 id="模块-e3-有害物质-rohs-reach" tabindex="-1">模块 E3　有害物质（RoHS / REACH） <a class="header-anchor" href="#模块-e3-有害物质-rohs-reach" aria-label="Permalink to &quot;模块 E3　有害物质（RoHS / REACH）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>问题</th><th>是</th><th>否</th><th>部分</th><th>备注</th></tr></thead><tbody><tr><td>E3.1</td><td>是否有物料中有害物质管控程序（REACH/RoHS合规管理）？</td><td></td><td></td><td></td><td></td></tr><tr><td>E3.2</td><td>是否要求所有物料供应商提供有害物质符合性声明（SVHC / RoHS Declaration）？</td><td></td><td></td><td></td><td></td></tr><tr><td>E3.3</td><td>是否对成品进行有害物质测试（由资质实验室）？</td><td></td><td></td><td></td><td></td></tr><tr><td>E3.4</td><td>焊接/喷涂工序使用的物质是否符合无铅标准（如适用）？</td><td></td><td></td><td></td><td></td></tr><tr><td>E3.5</td><td>废旧电子产品（工厂内产生的废品/返修品）是否由持证回收商处理？</td><td></td><td></td><td></td><td></td></tr></tbody></table><hr><h2 id="模块-e4-劳务派遣与临时工管理" tabindex="-1">模块 E4　劳务派遣与临时工管理 <a class="header-anchor" href="#模块-e4-劳务派遣与临时工管理" aria-label="Permalink to &quot;模块 E4　劳务派遣与临时工管理&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>问题</th><th>是</th><th>否</th><th>部分</th><th>备注</th></tr></thead><tbody><tr><td>E4.1</td><td>劳务派遣工占总工人比例是否≤10%（中国法规上限）？</td><td></td><td></td><td></td><td></td></tr><tr><td>E4.2</td><td>派遣工的工资待遇是否与同岗位正式工一致（同工同酬原则）？</td><td></td><td></td><td></td><td></td></tr><tr><td>E4.3</td><td>旺季使用的临时工是否签署了正式劳动合同（而非口头协议）？</td><td></td><td></td><td></td><td></td></tr><tr><td>E4.4</td><td>劳务派遣公司是否持有有效的人力资源服务许可证？</td><td></td><td></td><td></td><td></td></tr></tbody></table><hr><h2 id="模块-e5-供应链网络安全" tabindex="-1">模块 E5　供应链网络安全 <a class="header-anchor" href="#模块-e5-供应链网络安全" aria-label="Permalink to &quot;模块 E5　供应链网络安全&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>问题</th><th>是</th><th>否</th><th>部分</th><th>备注</th></tr></thead><tbody><tr><td>E5.1</td><td>是否对IT供应商（软件、云服务）进行安全评估后方可上线？</td><td></td><td></td><td></td><td></td></tr><tr><td>E5.2</td><td>关键生产系统的软件更新是否经过测试验证后才推送至生产环境？</td><td></td><td></td><td></td><td></td></tr><tr><td>E5.3</td><td>第三方维护人员（设备供应商）远程访问生产系统是否须经审批并记录？</td><td></td><td></td><td></td><td></td></tr><tr><td>E5.4</td><td>是否定期进行网络安全演练或渗透测试？</td><td></td><td></td><td></td><td></td></tr><tr><td>E5.5</td><td>是否有数据泄露/网络入侵的事件响应计划？</td><td></td><td></td><td></td><td></td></tr></tbody></table><hr><p><strong>授权签署</strong></p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td>法人代表/授权签署人</td><td>__________________</td></tr><tr><td>职务</td><td>__________________</td></tr><tr><td>日期</td><td>__________________</td></tr><tr><td>公章</td><td></td></tr></tbody></table>',23)])])}const c=d(e,[["render",o]]);export{b as __pageData,c as default};
